/**
 * NC coverage graph — typed loader for generated JSON data.
 *
 * @remarks
 * Generated by the NC coverage graph JSON writer.
 * Imports raw JSON data and re-exports it with TypeScript interfaces.
 */
import { createRequire } from 'node:module';
import type { NCCoverageGraph } from './types.js';

const require = createRequire(import.meta.url);
// Direct type annotation is acceptable here: NCCoverageGraph contains only
// primitive fields (string, number, Record<string, number>) with no union
// literals requiring runtime validation. See prior-knowledge-graph/index.ts
// for the two-step validation pattern used when union narrowing is needed.
const data: NCCoverageGraph = require('./data.json');

/**
 * NC coverage graph with National Curriculum statement mappings.
 *
 * @remarks
 * Contains National Curriculum statement coverage across units.
 * Use for curriculum planning and gap analysis.
 */
export const ncCoverageGraph: NCCoverageGraph = data;

export type { NCCoverageGraph, NCCoverageGraphStats, NCStatementNode } from './types.js';
